import{_ as t,c as o,ag as a,o as r}from"./chunks/framework.B1AvGRn6.js";const u=JSON.parse('{"title":"Draw Fixture Keyboard Accessibility","description":"","frontmatter":{},"headers":[],"relativePath":"using-ramp4/fixtures/draw-tools.md","filePath":"using-ramp4/fixtures/draw-tools.md"}'),i={name:"using-ramp4/fixtures/draw-tools.md"};function s(d,e,n,c,l,h){return r(),o("div",null,e[0]||(e[0]=[a('<h1 id="draw-fixture-keyboard-accessibility" tabindex="-1">Draw Fixture Keyboard Accessibility <a class="header-anchor" href="#draw-fixture-keyboard-accessibility" aria-label="Permalink to &quot;Draw Fixture Keyboard Accessibility&quot;">​</a></h1><p>The Draw fixture lets users create, edit, and manipulate graphics via mouse and keyboard controls. This document outlines the keyboard shortcuts available for users who prefer or require keyboard navigation.</p><h2 id="basic-controls" tabindex="-1">Basic Controls <a class="header-anchor" href="#basic-controls" aria-label="Permalink to &quot;Basic Controls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Key</th><th>Function</th></tr></thead><tbody><tr><td><code>Enter</code></td><td>Create a shape at the center of the map, or select a shape under the crosshair</td></tr><tr><td><code>Delete</code>/<code>Backspace</code></td><td>Delete the selected shape</td></tr><tr><td><code>Escape</code></td><td>Cancel current drawing operation or deselect current shape</td></tr></tbody></table><h2 id="moving-resizing-and-rotating-shapes" tabindex="-1">Moving, Resizing and Rotating Shapes <a class="header-anchor" href="#moving-resizing-and-rotating-shapes" aria-label="Permalink to &quot;Moving, Resizing and Rotating Shapes&quot;">​</a></h2><p>When a shape is selected, the following keyboard controls can be used to manipulate it:</p><h3 id="moving-shapes" tabindex="-1">Moving Shapes <a class="header-anchor" href="#moving-shapes" aria-label="Permalink to &quot;Moving Shapes&quot;">​</a></h3><p>Use the arrow keys to move the selected shape in the corresponding direction:</p><table tabindex="0"><thead><tr><th>Key</th><th>Movement</th></tr></thead><tbody><tr><td><code>↑</code> (Up Arrow)</td><td>Move shape up</td></tr><tr><td><code>↓</code> (Down Arrow)</td><td>Move shape down</td></tr><tr><td><code>←</code> (Left Arrow)</td><td>Move shape left</td></tr><tr><td><code>→</code> (Right Arrow)</td><td>Move shape right</td></tr></tbody></table><h3 id="resizing-shapes" tabindex="-1">Resizing Shapes <a class="header-anchor" href="#resizing-shapes" aria-label="Permalink to &quot;Resizing Shapes&quot;">​</a></h3><p>Hold <code>Shift</code> while pressing arrow keys to resize the selected shape:</p><table tabindex="0"><thead><tr><th>Key Combination</th><th>Resize Action</th></tr></thead><tbody><tr><td><code>Shift</code> + <code>↑</code> (Up Arrow)</td><td>Increase size vertically</td></tr><tr><td><code>Shift</code> + <code>↓</code> (Down Arrow)</td><td>Decrease size vertically</td></tr><tr><td><code>Shift</code> + <code>→</code> (Right Arrow)</td><td>Increase size horizontally</td></tr><tr><td><code>Shift</code> + <code>←</code> (Left Arrow)</td><td>Decrease size horizontally</td></tr></tbody></table><blockquote><p>Note: Resizing is not supported for point graphics.</p></blockquote><h3 id="rotating-shapes" tabindex="-1">Rotating Shapes <a class="header-anchor" href="#rotating-shapes" aria-label="Permalink to &quot;Rotating Shapes&quot;">​</a></h3><p>Hold <code>Alt</code> while pressing left or right arrow keys to rotate the selected shape:</p><table tabindex="0"><thead><tr><th>Key Combination</th><th>Rotation Action</th></tr></thead><tbody><tr><td><code>Alt</code> + <code>←</code> (Left Arrow)</td><td>Rotate counterclockwise</td></tr><tr><td><code>Alt</code> + <code>→</code> (Right Arrow)</td><td>Rotate clockwise</td></tr></tbody></table><blockquote><p>Note: Rotation is not supported for point graphics.</p></blockquote><h2 id="creating-multi-point-shapes-polylines-and-polygons" tabindex="-1">Creating Multi-Point Shapes (Polylines and Polygons) <a class="header-anchor" href="#creating-multi-point-shapes-polylines-and-polygons" aria-label="Permalink to &quot;Creating Multi-Point Shapes (Polylines and Polygons)&quot;">​</a></h2><p>The Draw fixture supports creating multi-point shapes (polylines and polygons) using keyboard controls:</p><ol><li>Activate polyline or polygon drawing mode</li><li>Press <code>Enter</code> to start multi-point mode and place the first point at the center of the map</li><li>Use arrow keys to position the crosshair for the next point</li><li>Press <code>Enter</code> to add additional points</li><li>To remove the last point added, press <code>Backspace</code> or <code>Delete</code></li><li>Press <code>Escape</code> to complete the shape (requires at least 2 points for polylines, 3 for polygons)</li></ol><h2 id="accessibility-announcements" tabindex="-1">Accessibility Announcements <a class="header-anchor" href="#accessibility-announcements" aria-label="Permalink to &quot;Accessibility Announcements&quot;">​</a></h2><p>The Draw fixture includes screen reader announcements for all actions, providing feedback when:</p><ul><li>A shape is created</li><li>A shape is selected/deselected</li><li>A shape is moved, resized, or rotated</li><li>A point is added or removed in multi-point mode</li><li>A drawing operation is completed or canceled</li></ul><p>These announcements help users with screen readers understand the current state and results of their actions.</p>',24)]))}const b=t(i,[["render",s]]);export{u as __pageData,b as default};
